struct LaplaceEquationFiniteDifferenceInput:Equatable,Sendable{let rows:Int;let columns:Int;let topBoundary:Double;let bottomBoundary:Double;let leftBoundary:Double;let rightBoundary:Double;let tolerance:Double;let maximumIterations:Int
 init(rows:Int,columns:Int,topBoundary:Double,bottomBoundary:Double,leftBoundary:Double,rightBoundary:Double,tolerance:Double=1e-8,maximumIterations:Int=10000){self.rows=rows;self.columns=columns;self.topBoundary=topBoundary;self.bottomBoundary=bottomBoundary;self.leftBoundary=leftBoundary;self.rightBoundary=rightBoundary;self.tolerance=tolerance;self.maximumIterations=maximumIterations}}
